import React, { useState } from "react";
import { Field, Form } from "react-final-form";
import { InputField } from "../../../common/InputText";
import { Error, PageMode, required } from "../../../common/Utilitis";
import SpecialityService from "../../services/speciality.service";

function AddUpdateForm(props) {
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState();
  const [file, setFile] = useState(
    props.mode === PageMode.Add ? null : props.selectedSpeciality?.image
  );
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

  const onSubmit = async (values) => {
    console.log(`onSubmit :: ${JSON.stringify(values, 0, 2)}`);
    setIsLoading(true);
    // await sleep(1500);
    // calling update profile API
    const specialityData = {
      name: values.name,
      active: true,
      image: file,
    };
    let response;
    if (props.mode === PageMode.Update) {
      response = await SpecialityService.updateSpeciality(
        props.selectedSpeciality?.id,
        specialityData
      );
    } else {
      response = await SpecialityService.createSpeciality(specialityData);
    }
    setIsLoading(false);
    if (!!!response.success && !response.success) {
      setMessage(!!response.message && response.message);
      return;
    }
    props.onClose(response.body);
  };

  const validate = async (values) => {
    const errors = {};
    if (!values.name) {
      errors.name = required;
    }
    if (!values.image) {
      errors.image = required;
    }
    return errors;
  };
  const convertBase64 = (file) => {
    return new Promise((resolve, reject) => {
      const fileReader = new FileReader();
      fileReader.readAsDataURL(file);

      fileReader.onload = () => {
        resolve(fileReader.result);
      };

      fileReader.onerror = (error) => {
        reject(error);
      };
    });
  };
  const uploadImage = async (e) => {
    const file = e.target.files[0];
    const base64 = await convertBase64(file);
    setFile(base64);
  };

  let specialityForm = (
    <Form
      validate={validate}
      onSubmit={onSubmit}
      initialValues={{
        name: props.selectedSpeciality?.name,
        image: props.selectedSpeciality?.image,
        isActive: props.selectedSpeciality?.isActive,
      }}
      render={({
        handleSubmit,
        onChange,
        submitError,
        form,
        submitting,
        pristine,
        values,
      }) => (
        <form onSubmit={handleSubmit} className="needs-validation" noValidate>
          {message && (
            <div className="invalid-feedback d-block mb-2">{message}</div>
          )}
          <div className="row form-row">
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>Name</label>
                <Field
                  name="name"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>Image</label>
                <Field name="image" showerrorbeside="true">
                  {({ input: { value, onChange, ...input } }) => (
                    <input
                      {...input}
                      type="file"
                      className="form-control floating"
                      onChange={(e) => {
                        onChange(e);
                        uploadImage(e);
                      }}
                    />
                  )}
                </Field>
                <Error name={"image"} showerrorbeside="true" />
              </div>
            </div>
          </div>
          <div className="submit-section">
            <button
              type="submit"
              className="btn btn-primary submit-btn"
              disabled={isLoading}
            >
              {!isLoading ? `Save` : ""}
              {isLoading && (
                <span className="spinner-border spinner-border-sm mb-1"></span>
              )}
            </button>
            <button
              className="btn btn-secondary submit-btn"
              onClick={(e) => {
                e.preventDefault();
                props.onClose(null);
              }}
            >
              Close
            </button>
          </div>
        </form>
      )}
    />
  );

  return <div>{specialityForm}</div>;
}
export default AddUpdateForm;
