import Alert from "@mui/material/Alert";
import CircularProgress from "@mui/material/CircularProgress";
import { useEffect, useState } from "react";
import { Modal } from "react-bootstrap";
import StickyBox from "react-sticky-box";
import DashboardSidebar from "../../../client/components/dashboard/sidebar/sidebar.jsx";
import DataTable from "../../../common/DataTable";
import { PageMode, TableInputType } from "../../../common/Utilitis";
import SpecialityService from "../../services/speciality.service";
import AddUpdateForm from "./AddUpdateForm";
import { useTranslation } from "react-i18next";
function SpecialitiesList() {
  const [t, i18n] = useTranslation();
  const [loading, setLoading] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [show, setShow] = useState(false);
  const [showDelete, setShowDelete] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [message, setMessage] = useState();
  const [messageDelete, setMessageDelete] = useState();
  const [specialitiesData, setSpecialitiesData] = useState();
  const [selectedSpeciality, setSelectedSpeciality] = useState(null);
  const [page, setPage] = useState(1);
  const [dataPage, setDataPage] = useState();
  const [pageIndex, setPageIndex] = useState(0);
  const [mode, setMode] = useState(PageMode.Add);
  const handleClose = () => setShow(false);
  const handleShow = () => {
    setShow(true);
    setShowSuccess(false);
  };
  const handleCloseDelete = () => setShowDelete(false);
  const handleShowDelete = () => {
    setShowDelete(true);
    setShowSuccess(false);
  };

  useEffect(async () => {
    setLoading(true);
    const response = await SpecialityService.getAllSpecialities(pageIndex, 10);
    setMessage(!!response?.message && response?.message);
    if (response.success) {
      setSpecialitiesData(
        response.body?.map((s) => {
          return { ...s, isActive: s.isActive };
        })
      );
      setDataPage({ ...response?.pagingation });
    }

    setLoading(false);
  }, [pageIndex]);

  const handlePageChange = (event, value) => {
    setPageIndex(value - 1);
    setPage(value);
    setShowSuccess(false);
  };

  const deleteSpecialityHandler = async (id) => {
    setDeleting(true);

    const response = await SpecialityService.deleteSpeciality(id);

    setDeleting(false);
    if (!!!response.success && !response.success) {
      setMessageDelete(!!response.message && response.message);
      return;
    }
    handleCloseDelete();
    if (specialitiesData?.length === 1) {
      setPageIndex(pageIndex - 1);
    }

    setSpecialitiesData(specialitiesData.filter((u) => u.id != id));
  };

  const updateSpecialityStatusHandler = async (id, isActive) => {
    setLoading(true);
    const response = await SpecialityService.updateSpeciality(id, {
      isActive: !isActive,
    });

    if (!!!response.success && !response.success) {
      // To-Do: implemet error msg
      setLoading(false);
      return;
    }

    setSpecialitiesData(
      specialitiesData?.map((s) => {
        return s.id === response?.body?.id
          ? { ...s, isActive: response?.body?.isActive }
          : s;
      })
    );
    setLoading(false);
  };

  const columns = [
    { id: "name", label: "Name" },
    { id: "active", label: "Active", type: TableInputType.Toggle },
    { id: "image", label: "Specialities", type: TableInputType.Image },
  ];
  let tableContent = (
    <DataTable
      columns={columns}
      rows={specialitiesData}
      onPageChange={handlePageChange}
      totalPages={dataPage?.totalPages}
      page={page}
      showActions={true}
      onUpdateStatus={(speciality) => {
        updateSpecialityStatusHandler(speciality.id, speciality.isActive);
      }}
      onEdit={(speciality) => {
        handleShow();
        setSelectedSpeciality(speciality);
        setMode(PageMode.Update);
      }}
      onDelete={(speciality) => {
        handleShowDelete();
        setSelectedSpeciality(speciality);
        setMessageDelete(null);
      }}
    />
  );

  return (
    <div>
      <div className="content">
        <div className="container-fluid">
          <div className="row">
            <div className="col-md-5 col-lg-4 col-xl-3 theiaStickySidebar">
              <StickyBox offsetTop={20} offsetBottom={20}>
                <DashboardSidebar />
              </StickyBox>
            </div>
            <div className="col-md-7 col-lg-8 col-xl-9">
              <div className="row">
                <div className="col-sm-12">
                  <div className="card">
                    <div className="card-header">
                      <h4 className="card-title float-left">
                        Specialities List
                      </h4>
                      <button
                        className="btn btn-primary float-right"
                        onClick={() => {
                          handleShow();
                          setSelectedSpeciality(null);
                          setMode(PageMode.Add);
                        }}
                        data-toggle="modal"
                      >
                        Add
                      </button>
                    </div>
                    <div className="card-body ">
                      <div className="card card-table mb-0">
                        <div className="card-body">
                          <div className="table-responsive">
                            <div className="invalid-feedback d-block mb-2">
                              {message}
                            </div>
                            {loading ? (
                              <div className="centered">
                                <h4>
                                  <div>
                                    <CircularProgress />
                                  </div>
                                  <div>
                                    <span style={{ color: "#15558d" }}>
                                      {t("GettingSpecialities")}
                                    </span>
                                  </div>
                                </h4>
                              </div>
                            ) : (
                              <>
                                {showSuccess ? (
                                  <div style={{ margin: "20px" }}>
                                    <Alert severity="success">{`Speciality have been ${mode} successfully!`}</Alert>
                                  </div>
                                ) : (
                                  <></>
                                )}
                                {tableContent}
                              </>
                            )}
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <Modal
        show={show}
        onHide={handleClose}
        size="lg"
        scrollable={true}
        aria-labelledby="example-modal-sizes-title-sm"
      >
        <Modal.Header>
          <h5 className="modal-title">{`${mode} Speciality`}</h5>
          <button
            type="button"
            className="close"
            data-dismiss="modal"
            aria-label="Close"
            onClick={handleClose}
          >
            <span aria-hidden="true">×</span>
          </button>
        </Modal.Header>
        <Modal.Body>
          <div className="modal-body">
            <div>
              <AddUpdateForm
                selectedSpeciality={selectedSpeciality}
                mode={mode}
                onClose={(speciality) => {
                  handleClose();
                  if (speciality) {
                    if (mode === PageMode.Update) {
                      const updatedSpecialities = specialitiesData.map((u) => {
                        return u.id === speciality.id
                          ? {
                              ...speciality,
                            }
                          : u;
                      });
                      setSpecialitiesData(updatedSpecialities);
                    } else {
                      const addedSpeciality = {
                        ...speciality,
                      };
                      if (specialitiesData?.length === 10) {
                        setDataPage({
                          ...dataPage,
                          totalPages: dataPage.totalPages + 1,
                        });
                      }
                      setSpecialitiesData([
                        ...specialitiesData,
                        addedSpeciality,
                      ]);
                    }
                    setShowSuccess(true);
                  }
                }}
              />
            </div>
          </div>
        </Modal.Body>
      </Modal>

      <Modal
        show={showDelete}
        onHide={handleCloseDelete}
        aria-labelledby="example-modal-sizes-title-sm"
        centered
      >
        <Modal.Header>
          <h5 className="modal-title">Delete Speciality Confirmation</h5>
          <button
            type="button"
            className="close"
            data-dismiss="modal"
            aria-label="Close"
            onClick={handleCloseDelete}
          >
            <span aria-hidden="true">×</span>
          </button>
        </Modal.Header>
        <Modal.Body>
          <div className="modal-body">
            {messageDelete && (
              <div className="invalid-feedback d-block mb-2">
                {messageDelete}
              </div>
            )}
            <h5 style={{ color: "red" }}>
              Are you sure you want to delete the following speciality?
            </h5>
            <div>
              <b>Speciality:</b>
              {` ${selectedSpeciality?.name} `}
              <div>
                <img
                  src={selectedSpeciality?.image}
                  alt={selectedSpeciality?.name}
                />
              </div>
            </div>
          </div>
        </Modal.Body>
        <Modal.Footer>
          <button
            className="btn btn-danger submit-btn"
            disabled={deleting}
            onClick={() => {
              deleteSpecialityHandler(selectedSpeciality.id);
            }}
          >
            {!deleting ? `Delete` : ""}
            {deleting && (
              <span className="spinner-border spinner-border-sm mb-1"></span>
            )}
          </button>
          <button
            className="btn btn-secondary submit-btn"
            onClick={handleCloseDelete}
          >
            Close
          </button>
        </Modal.Footer>
      </Modal>
    </div>
  );
}
export default SpecialitiesList;
